#include "interface.h"

#include <stdint.h>
#include <stdlib.h>

static uint64_t checksum_i16(const int16_t* data, size_t n) {
  uint64_t hash = 1469598103934665603ULL;
  for (size_t i = 0; i < n; ++i) {
    hash ^= (uint16_t)data[i];
    hash *= 1099511628211ULL;
  }
  return hash;
}

uint64_t run(const int16_t* src, int input_len, int output_len, int iters) {
  if (output_len <= 0) return 0;

  int16_t* out = (int16_t*)malloc((size_t)output_len * sizeof(int16_t));
  if (!out) return 0;

  uint64_t hash = 0;

  // Pre-calculate constants for fixed-point arithmetic
  // We use 32.32 fixed point for the position to maintain precision
  uint64_t step_fixed = 0;
  if (output_len > 1) {
    step_fixed = ((uint64_t)(input_len - 1) << 32) / (output_len - 1);
  }

  for (int iter = 0; iter < iters; ++iter) {
    for (int i = 0; i < output_len; ++i) {
      uint64_t pos_fixed = (uint64_t)i * step_fixed;
      int left = (int)(pos_fixed >> 32);
      uint32_t frac_fixed = (uint32_t)(pos_fixed & 0xFFFFFFFF);

      int right = left + 1;
      if (right >= input_len) right = input_len - 1;

      // Linear interpolation: sample = src[left] + frac * (src[right] - src[left])
      // Using 64-bit integer to prevent overflow during multiplication
      int32_t diff = src[right] - src[left];
      int64_t interpolated = (int64_t)src[left] << 32;
      interpolated += (int64_t)diff * frac_fixed;

      // Rounding: add 0.5 (which is 2^31 in our 32.32 fixed point)
      // For positive numbers: (val + 0.5) floor
      // For negative numbers: (val - 0.5) floor
      if (interpolated >= 0) {
        out[i] = (int16_t)((interpolated + (1LL << 31)) >> 32);
      } else {
        out[i] = (int16_t)((interpolated - (1LL << 31)) >> 32);
      }
    }
    hash = checksum_i16(out, (size_t)output_len);
  }

  free(out);
  return hash;
}
